const d = JSON.parse(msg.payload);
if (!d.device_id || d.active_power_kw === undefined) return null;
if (d.quality !== 'GOOD') {
  msg.topic = `mdt/${d.site_id}/alerts/${d.device_id}`;
  msg.payload = JSON.stringify({ ts: d.ts, device_id: d.device_id, alarm: 'BAD_QUALITY' });
  return [null, msg];
}
msg.payload = d;
return [msg, null];

const d = msg.payload;
// Apparent power (if missing)
if (d.active_power_kw && d.power_factor && !d.apparent_power_kva) {
  d.apparent_power_kva = +(d.active_power_kw / d.power_factor).toFixed(2);
}
// CO2 (Morocco ONEE factor 0.718 kgCO2/kWh)
if (d.energy_kwh !== undefined) {
  d.co2_kg = +(d.energy_kwh * 0.718).toFixed(4);
}
// Voltage unbalance
if (d.voltage_l1_v && d.voltage_l2_v && d.voltage_l3_v) {
  const avg = (d.voltage_l1_v + d.voltage_l2_v + d.voltage_l3_v) / 3;
  const maxDev = Math.max(Math.abs(d.voltage_l1_v - avg), Math.abs(d.voltage_l2_v - avg), Math.abs(d.voltage_l3_v - avg));
  d.voltage_unbalance_pct = +((maxDev / avg) * 100).toFixed(2);
  if (d.voltage_unbalance_pct > 2.0) node.warn(`Voltage unbalance ${d.voltage_unbalance_pct}% on ${d.device_id}`);
}
msg.payload = d;
return msg;

const d = msg.payload;
const metrics = [
  ['active_power_kw',       d.active_power_kw],
  ['reactive_power_kvar',   d.reactive_power_kvar],
  ['apparent_power_kva',    d.apparent_power_kva],
  ['power_factor',          d.power_factor],
  ['voltage_l1_v',          d.voltage_l1_v],
  ['voltage_l2_v',          d.voltage_l2_v],
  ['voltage_l3_v',          d.voltage_l3_v],
  ['current_l1_a',          d.current_l1_a],
  ['frequency_hz',          d.frequency_hz],
  ['thd_voltage_pct',       d.thd_voltage_pct],
  ['thd_current_pct',       d.thd_current_pct],
  ['energy_kwh',            d.energy_kwh],
  ['energy_kvarh',          d.energy_kvarh],
  ['co2_kg',                d.co2_kg],
  ['voltage_unbalance_pct', d.voltage_unbalance_pct],
  ['demand_kw_15min',       d.demand_kw_15min],
];
const ts = new Date(d.ts).toISOString();
const messages = metrics
  .filter(([_, v]) => v !== undefined && v !== null)
  .map(([metric, value]) => ({
    payload: {
      query: 'INSERT INTO raw_measurements(time,device_id,device_type,site_id,metric,value,quality) VALUES($1,$2,$3,$4,$5,$6,$7)',
      params: [ts, d.device_id, 'meter', d.site_id, metric, value, d.quality]
    }
  }));
return [messages];
